parameters.jsCode:
// Tally error counts per agent (role) from the last hour's Langfuse traces.
// Each trace has: id, name, metadata {agent_role, app_id}, observations[] (contains level=ERROR entries).
// An agent is 'unhealthy' if it has >= 3 errors in the hour.
const resp = $input.first().json;
const status = resp.statusCode || 0;
if (status !== 200) {
  return [{ json: { skip: true, reason: `langfuse ${status}`, details: JSON.stringify(resp.body || {}).slice(0, 300) } }];
}

const traces = resp.body?.data || [];
const byRole = {};
for (const t of traces) {
  const role = t.metadata?.agent_role || t.userId || 'unknown';
  if (!byRole[role]) byRole[role] = { total: 0, errors: 0, sample: null };
  byRole[role].total++;
  // Level-based classification — tolerate different Langfuse shapes.
  const isError = (t.level === 'ERROR') || (t.observations || []).some(o => o.level === 'ERROR' || o.statusMessage?.includes('error'));
  if (isError) {
    byRole[role].errors++;
    if (!byRole[role].sample) byRole[role].sample = { traceId: t.id, name: t.name, timestamp: t.timestamp, message: (t.observations || []).find(o => o.level === 'ERROR')?.statusMessage || 'unknown' };
  }
}

const unhealthy = Object.entries(byRole)
  .filter(([, v]) => v.errors >= 3)
  .map(([role, v]) => ({ role, ...v }));

return [{
  json: {
    skip: unhealthy.length === 0,
    reason: unhealthy.length === 0 ? 'happy path' : 'agents_with_3plus_errors',
    tracesScanned: traces.length,
    unhealthy,
  }
}];

parameters.text:
